-- ─── 7. CROSS_SUBJECT edges ──────────────────────────────────────────────────
INSERT INTO curriculum_edges ("id","sourceId","targetId","relationship","weight","createdAt")
SELECT gen_random_uuid()::TEXT, a."id", b."id", 'CROSS_SUBJECT'::"EdgeRelation", 0.8, now()
FROM (VALUES
  -- Maths ↔ Physics (shared mathematical concepts)
  ('Differentiation','Speed, Velocity & Acceleration'),
  ('Vectors','Scalars & Vectors'),
  ('Basic Trigonometric Ratios','Waves'),
  ('Exponential & Logarithmic Functions','Atomic Structure & Radioactivity'),
  -- Maths ↔ Biology (probability/statistics in genetics)
  ('Statistics','Genetics & Variation'),
  ('Probability','Genetics & Variation'),
  -- Chemistry ↔ Physics (atomic theory overlap)
  ('Atomic Structure','Atomic Structure & Radioactivity'),
  ('Chemical Bonding','Waves'),
  -- Chemistry ↔ Biology (biochemistry overlap)
  ('Rates of Reaction','Enzymes'),
  ('Organic Chemistry','Biological Molecules'),
  ('Nitrogen & its Compounds','Nutrient Cycles'),
  ('Carbon & its Allotropes','Nutrient Cycles'),
  ('Water & Solutions','Movement Into & Out of Cells'),
  ('Pharmaceuticals & Dyes','Disease & Public Health'),
  -- Physics ↔ Biology (environment and energy)
  ('Energy Sources & Power Transmission','Environmental Pollution'),
  -- Economics ↔ Government (policy and governance)
  ('Fiscal Policy','Arms of Government'),
  ('International Trade','Globalisation & its Effects'),
  ('Agricultural Development in Nigeria','Agriculture & Food Production'),
  -- Literature ↔ English Language (shared rhetorical skills)
  ('Literary Devices & Figures of Speech','Figures of Speech in Language'),
  ('Writing a Literary Essay','Essay Writing - Argumentative')
) AS pairs(src, tgt)
JOIN curriculum_nodes a ON a."label" = pairs.src AND a."schoolId" IS NULL
JOIN curriculum_nodes b ON b."label" = pairs.tgt AND b."schoolId" IS NULL;

